import React from 'react';
import { FlaskConical, Code2, Bug, ArrowRight, Zap } from 'lucide-react';

const features = [
  {
    id: 'testcases',
    icon: FlaskConical,
    color: '#534AB7',
    bg: '#EEEDFE',
    title: 'Test Case Generator',
    desc: 'Generate positive, negative, validation & boundary test cases from module descriptions.',
    actions: ['Import Excel/CSV', 'Export to Excel/CSV', 'Edit & review'],
  },
  {
    id: 'automation',
    icon: Code2,
    color: '#1D9E75',
    bg: '#E1F5EE',
    title: 'Automation Scripts',
    desc: 'Convert your test cases into ready-to-run Playwright or Selenium JavaScript scripts.',
    actions: ['Playwright JS', 'Selenium JS', 'Download ZIP'],
  },
  {
    id: 'bugreports',
    icon: Bug,
    color: '#D85A30',
    bg: '#FAECE7',
    title: 'Bug Report Generator',
    desc: 'Create standardized bug reports with severity, priority, and reproduction steps.',
    actions: ['Auto severity', 'Steps to reproduce', 'Structured output'],
  },
];

const stats = [
  { label: 'Manual effort saved', value: '70%+' },
  { label: 'Script gen speed', value: '30s' },
  { label: 'Frameworks', value: '2' },
  { label: 'Export formats', value: '2' },
];

export default function Dashboard({ onNavigate }) {
  return (
    <div>
      {/* Hero */}
      <div style={{ marginBottom: 28 }}>
        <div style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 6,
          background: '#EEEDFE',
          color: '#534AB7',
          padding: '4px 10px',
          borderRadius: 20,
          fontSize: 11,
          fontWeight: 600,
          marginBottom: 12,
        }}>
          <Zap size={11} />
          AI-POWERED QA PLATFORM
        </div>
        <h1 style={{ fontSize: 26, marginBottom: 8 }}>Welcome to QA Assistant</h1>
        <p style={{ color: '#555', maxWidth: 520 }}>
          Generate test cases, automation scripts, and bug reports in seconds.
          Built for QA engineers who want to move faster.
        </p>
      </div>

      {/* Stats */}
      <div className="stats-row">
        {stats.map(s => (
          <div className="stat-card" key={s.label}>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
          </div>
        ))}
      </div>

      {/* Feature Cards */}
      <div style={{ display: 'grid', gap: 16 }}>
        {features.map(f => {
          const Icon = f.icon;
          return (
            <div key={f.id} className="card" style={{ display: 'flex', gap: 20, padding: '20px 24px' }}>
              <div style={{
                width: 44,
                height: 44,
                borderRadius: 10,
                background: f.bg,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0,
              }}>
                <Icon size={20} color={f.color} />
              </div>

              <div style={{ flex: 1 }}>
                <h2 style={{ marginBottom: 4 }}>{f.title}</h2>
                <p style={{ color: '#666', fontSize: 13, marginBottom: 12 }}>{f.desc}</p>
                <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 14 }}>
                  {f.actions.map(a => (
                    <span key={a} style={{
                      fontSize: 11,
                      padding: '3px 8px',
                      borderRadius: 4,
                      background: '#f5f4fc',
                      color: '#555',
                      border: '1px solid #e2e0f0',
                    }}>{a}</span>
                  ))}
                </div>
                <button
                  className="btn btn-primary btn-sm"
                  onClick={() => onNavigate(f.id)}
                >
                  Open {f.title.split(' ')[0]} <ArrowRight size={13} />
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Phase 2 teaser */}
      <div style={{
        marginTop: 24,
        background: '#1a1a2e',
        borderRadius: 12,
        padding: '20px 24px',
        display: 'flex',
        alignItems: 'center',
        gap: 16,
      }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 11, fontWeight: 600, color: '#7F77DD', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>Coming in Phase 2</div>
          <div style={{ color: '#cdd6f4', fontSize: 14, fontWeight: 500 }}>URL & Screenshot-based generation · API test cases · Postman collections</div>
        </div>
        <div style={{ fontSize: 11, color: '#534AB7', background: '#EEEDFE', padding: '4px 10px', borderRadius: 20, fontWeight: 600, whiteSpace: 'nowrap' }}>Roadmap →</div>
      </div>
    </div>
  );
}
